#include <stdio.h>

static long long binom(long long n, long long r){
    if(r<0||r>n) return 0;
    if(r>n-r) r=n-r;
    long long res=1;
    for(long long i=1;i<=r;++i){
        res=res*(n-r+i)/i;
    }
    return res;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long n,k; scanf("%lld %lld",&n,&k);
        printf("%lld\n", binom(n-1,k-1));
    }
    return 0;
}

