import sys

def binom(n,r):
    if r<0 or r>n:
        return 0
    if r>n-r:
        r=n-r
    res=1
    for i in range(1,r+1):
        res=res*(n-r+i)//i
    return res

def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        n=int(next(it)); k=int(next(it))
        out.append(str(binom(n-1,k-1)))
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

